/*
 * Symmetric Cipher Model - Caesar Cipher in C
 * =============================================
 * Demonstrates the five components of symmetric cipher:
 * 1. Plaintext (P)    - Original message input
 * 2. Secret Key (K)   - Shared secret for encryption/decryption
 * 3. Encryption (E)  - Transform plaintext to ciphertext
 * 4. Ciphertext (C)  - Encrypted output
 * 5. Decryption (D)  - Transform ciphertext back to plaintext
 * 
 * Formulas: C = E(K, P) and P = D(K, C)
 */

#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MAX_LENGTH 100

/*
 * Encryption Function: C = E(K, P)
 * Shifts each alphabetic character by K positions
 */
void encrypt(char *plaintext, char *ciphertext, int key) {
    int i = 0;

    while (plaintext[i] != '\0') {
        if (isalpha(plaintext[i])) {
            char base = isupper(plaintext[i]) ? 'A' : 'a';
            /* Shift character: C = (P + K) mod 26 */
            ciphertext[i] = ((toupper(plaintext[i]) - 'A' + key) % 26) + base;
        } else {
            ciphertext[i] = plaintext[i];  /* Preserve non-alphabetic */
        }
        i++;
    }
    ciphertext[i] = '\0';
}

/*
 * Decryption Function: P = D(K, C)
 * Reverses the encryption using the SAME key
 * This demonstrates the symmetric property
 */
void decrypt(char *ciphertext, char *plaintext, int key) {
    int i = 0;

    while (ciphertext[i] != '\0') {
        if (isalpha(ciphertext[i])) {
            char base = isupper(ciphertext[i]) ? 'A' : 'a';
            /* Reverse shift: P = (C - K) mod 26 */
            int shifted = ((toupper(ciphertext[i]) - 'A' - key) % 26);
            if (shifted < 0) shifted += 26;  /* Handle negative modulo */
            plaintext[i] = shifted + base;
        } else {
            plaintext[i] = ciphertext[i];
        }
        i++;
    }
    plaintext[i] = '\0';
}

/* Function to convert string to uppercase */
void toUpperCase(char *str) {
    int i = 0;
    while (str[i] != '\0') {
        str[i] = toupper(str[i]);
        i++;
    }
}

int main() {
    char plaintext[MAX_LENGTH];
    char ciphertext[MAX_LENGTH];
    char recovered[MAX_LENGTH];
    int key;

    printf("================================================\n");
    printf("   SYMMETRIC CIPHER MODEL - CAESAR CIPHER\n");
    printf("================================================\n\n");

    /* Input the five components */
    printf("--- Input Components ---\n");
    printf("Enter Plaintext (P): ");
    fgets(plaintext, MAX_LENGTH, stdin);
    plaintext[strcspn(plaintext, "\n")] = 0;  /* Remove newline */

    printf("Enter Secret Key (K): ");
    scanf("%d", &key);

    /* Ensure key is within 0-25 range */
    key = key % 26;

    printf("\n--- Five Components of Symmetric Cipher ---\n");
    printf("1. Plaintext (P):     %s\n", plaintext);
    printf("2. Secret Key (K):    %d\n", key);
    printf("3. Encryption (E):    Shift letters by %d positions\n", key);

    /* Encryption: C = E(K, P) */
    toUpperCase(plaintext);
    encrypt(plaintext, ciphertext, key);

    printf("4. Ciphertext (C):    %s\n", ciphertext);
    printf("5. Decryption (D):    Reverse shift by %d positions\n", key);

    /* Decryption: P = D(K, C) - using SAME key (symmetric) */
    printf("\n--- Encryption Process: C = E(K, P) ---\n");
    printf("Input:  Plaintext  = \"%s\"\n", plaintext);
    printf("Key:    K = %d\n", key);
    printf("Output: Ciphertext = \"%s\"\n", ciphertext);

    printf("\n--- Decryption Process: P = D(K, C) ---\n");
    printf("Input:  Ciphertext = \"%s\"\n", ciphertext);
    printf("Key:    K = %d (SAME KEY - symmetric property)\n", key);

    decrypt(ciphertext, recovered, key);
    printf("Output: Plaintext  = \"%s\"\n", recovered);

    printf("\n--- Kerckhoffs's Principle Demonstration ---\n");
    printf("The encryption algorithm is known (shift by K).\n");
    printf("Security depends ONLY on key secrecy.\n\n");

    /* Show what happens with wrong key */
    printf("--- Attack Attempt (Wrong Key) ---\n");
    char wrong[MAX_LENGTH];
    decrypt(ciphertext, wrong, 7);
    printf("Using wrong key K=7: %s (unreadable)\n", wrong);

    return 0;
}
